"""matplotlib.animation — animation stubs for OfflinAi."""


class Animation:
    """Base animation class."""

    def __init__(self, fig, event_source=None, blit=False):
        self._fig = fig

    def save(self, filename, writer=None, fps=None, dpi=None, codec=None,
             bitrate=None, extra_args=None, metadata=None, extra_anim=None,
             savefig_kwargs=None):
        pass

    def to_html5_video(self, embed_limit=None):
        return ''

    def to_jshtml(self, fps=None, embed_frames=True, default_mode=None):
        return ''

    def pause(self):
        pass

    def resume(self):
        pass


class TimedAnimation(Animation):
    def __init__(self, fig, interval=200, repeat_delay=0, repeat=True, event_source=None, *args, **kwargs):
        super().__init__(fig, event_source)


class FuncAnimation(TimedAnimation):
    """Function-based animation."""

    def __init__(self, fig, func, frames=None, init_func=None, fargs=None,
                 save_count=None, *, cache_frame_data=True, **kwargs):
        super().__init__(fig, **kwargs)
        self._func = func
        self._frames = frames
        self._init_func = init_func
        self._fargs = fargs or ()
        self._save_count = save_count


class ArtistAnimation(TimedAnimation):
    """Artist-based animation."""

    def __init__(self, fig, artists, *args, **kwargs):
        super().__init__(fig, *args, **kwargs)
        self._artists = artists


